}

import { type HTMLAttributes } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "../../lib/utils.js";

/**
 * Badge variants — monochrome palette with subtle tonal shifts for
 * semantic meaning. Uses px-based rounding (not rounded-full) so badges
 * pick up the global radius token. Plan-state badges use gray-scale tints
 * to stay within the neutral design direction.
 */
const badgeVariants = cva(
  "inline-flex items-center rounded-sm border px-2.5 py-0.5 text-xs font-semibold tracking-wide transition-colors",
  {
    variants: {
      variant: {
        default: "border-border bg-muted-bg text-foreground",
        primary: "border-foreground/20 bg-foreground/5 text-foreground",
        success: "border-foreground/25 bg-foreground/5 text-foreground",
        warning: "border-foreground/15 bg-foreground/[0.03] text-muted",
        danger: "border-foreground/30 bg-foreground/8 text-foreground font-bold",
        /* Plan-state badges: monochrome tonal variations */
        draft: "border-border bg-muted-bg text-muted",
        locked: "border-foreground/20 bg-foreground/5 text-foreground",
        reconciling: "border-foreground/15 bg-foreground/[0.03] text-muted",
        reconciled: "border-foreground/25 bg-foreground/5 text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  },
);

export interface BadgeProps
  extends HTMLAttributes<HTMLSpanElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <span className={cn(badgeVariants({ variant, className }))} {...props} />
  );
}

export { Badge, badgeVariants };

import { forwardRef, type ButtonHTMLAttributes } from "react";
import { cva, type VariantProps } from "class-variance-authority";
import { cn } from "../../lib/utils.js";

/**
 * Button variants — monochrome design system.
 * Primary uses the neutral gray (#737373) with white foreground.
 * All corners are sharp (radius comes from the global token = 0).
 */
const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
  {
    variants: {
      variant: {
        primary:
          "bg-foreground text-primary-foreground shadow-sm hover:bg-foreground/90 active:bg-foreground/80",
        secondary:
          "border border-border bg-surface text-foreground shadow-sm hover:bg-muted-bg active:bg-muted-bg/80",
        ghost:
          "text-foreground hover:bg-muted-bg active:bg-muted-bg/80",
        danger:
          "bg-danger text-danger-foreground shadow-sm hover:bg-danger/90 active:bg-danger/80",
        success:
          "bg-success text-success-foreground shadow-sm hover:bg-success/90 active:bg-success/80",
        link:
          "text-foreground underline-offset-4 hover:underline p-0 h-auto",
      },
      size: {
        sm: "h-8 rounded-sm px-3 text-xs",
        md: "h-9 rounded-default px-4 text-sm",
        lg: "h-10 rounded-md px-5 text-sm",
        icon: "h-9 w-9 rounded-default",
      },
    },
    defaultVariants: {
      variant: "primary",
      size: "md",
    },
  },
);

export interface ButtonProps
  extends ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {}

const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, ...props }, ref) => (
    <button
      ref={ref}
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  ),
);
Button.displayName = "Button";

export { Button, buttonVariants };

/**
 * Toast notification system.
 * Can be driven by the HostBridge NotificationBridge or used standalone.
 */
import { useState, useCallback, createContext, useContext, type ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "../../lib/utils.js";
import { X } from "lucide-react";

/* ── Toast Variant Styles ──────────────────────────────────────────── */

const toastVariants = cva(
  "pointer-events-auto flex items-center gap-3 rounded-default border px-4 py-3 text-sm shadow-lg transition-all",
  {
    variants: {
      type: {
        success: "border-success/30 bg-success/10 text-success",
        info: "border-primary/30 bg-primary/10 text-primary",
        warning: "border-warning/30 bg-warning/10 text-warning",
        error: "border-danger/30 bg-danger/10 text-danger",
      },
    },
    defaultVariants: { type: "info" },
  },
);

/* ── Types ─────────────────────────────────────────────────────────── */

interface ToastItem {
  id: string;
  type: "success" | "info" | "warning" | "error";
  message: string;
}

interface ToastContextValue {
  showToast(options: {
    type: "success" | "info" | "warning" | "error";
    message: string;
    durationMs?: number;
  }): void;
}

/* ── Context ───────────────────────────────────────────────────────── */

const ToastContext = createContext<ToastContextValue | null>(null);

function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext);
  if (!ctx) throw new Error("useToast must be used within <ToastProvider>");
  return ctx;
}

/* ── Provider ──────────────────────────────────────────────────────── */

let toastCounter = 0;

function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<ToastItem[]>([]);

  const showToast = useCallback(
    (options: {
      type: "success" | "info" | "warning" | "error";
      message: string;
      durationMs?: number;
    }) => {
      const id = `toast-${++toastCounter}`;
      setToasts((prev) => [...prev, { id, type: options.type, message: options.message }]);
      setTimeout(() => {
        setToasts((prev) => prev.filter((t) => t.id !== id));
      }, options.durationMs ?? 4000);
    },
    [],
  );

  const dismiss = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      {/* Toast container */}
      <div
        aria-live="polite"
        className="pointer-events-none fixed bottom-4 right-4 z-[100] flex flex-col gap-2"
      >
        {toasts.map((t) => (
          <div key={t.id} className={cn(toastVariants({ type: t.type }))}>
            <span className="flex-1">{t.message}</span>
            <button
              type="button"
              onClick={() => dismiss(t.id)}
              className="pointer-events-auto rounded-sm p-0.5 opacity-70 hover:opacity-100"
              aria-label="Dismiss"
            >
              <X className="h-3.5 w-3.5" />
            </button>
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
}

export { ToastProvider, useToast, toastVariants };

